public int longestSubarrayWithSumK() {
    int[] nums = {1, -1, 5, -2, 3};
    int k = 3;

    Map<Integer, Integer> prefixSumIndices = new HashMap<>();
    prefixSumIndices.put(0, -1);

    int prefixSum = 0;
    int maxLength = 0;

    for (int i = 0; i < nums.length; i++) {
        prefixSum += nums[i];

        if (prefixSumIndices.containsKey(prefixSum - k)) {
            maxLength = Math.max(maxLength, i - prefixSumIndices.get(prefixSum - k));
        }

        prefixSumIndices.putIfAbsent(prefixSum, i);
    }

    return maxLength;
}

public int maxPathSum() {
    TreeNode root = new TreeNode(1);
    root.left = new TreeNode(2);
    root.right = new TreeNode(3);

    int[] maxSum = new int[]{Integer.MIN_VALUE};
    maxGain(root, maxSum);
    return maxSum[0];
}

private int maxGain(TreeNode node, int[] maxSum) {
    if (node == null) return 0;

    int leftGain = Math.max(maxGain(node.left, maxSum), 0);
    int rightGain = Math.max(maxGain(node.right, maxSum), 0);

    int priceNewPath = node.val + leftGain + rightGain;
    maxSum[0] = Math.max(maxSum[0], priceNewPath);

    return node.val + Math.max(leftGain, rightGain);
}

public boolean isPalindrome() {
    String s = "racecar";

    int left = 0;
    int right = s.length() - 1;

    while (left < right) {
        if (s.charAt(left) != s.charAt(right)) {
            return false;
        }
        left++;
        right--;
    }

    return true;
}

public int lengthOfLongestSubstring() {
    String s = "abcabcbb";

    Set<Character> set = new HashSet<>();
    int left = 0;
    int max = 0;

    for (int right = 0; right < s.length(); right++) {
        while (set.contains(s.charAt(right))) {
            set.remove(s.charAt(left));
            left++;
        }

        set.add(s.charAt(right));
        max = Math.max(max, right - left + 1);
    }

    return max;
}

