private int maxGain(TreeNode node, int[] maxSum) {
    if (node == null) return 0;

    int left = Math.max(maxGain(node.left, maxSum), 0);
    int right = Math.max(maxGain(node.right, maxSum), 0);

    int price = node.val + left + right;
    maxSum[0] = Math.max(maxSum[0], price);

    return node.val + Math.max(left, right);
}

public int findKthLargest() {
    int[] nums = {3, 2, 1, 5, 6, 4};
    int k = 2;

    PriorityQueue<Integer> minHeap = new PriorityQueue<>();

    for (int num : nums) {
        minHeap.offer(num);
        if (minHeap.size() > k) {
            minHeap.poll();
        }
    }

    return minHeap.peek();
}
